class ModelDownloader:
    def __init__(self, cache_dir='./model_cache'):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(parents=True, exist_ok=True)
        
    def download_file(self, url, filename=None):
        if filename is None:
            filename = hashlib.md5(url.encode()).hexdigest() + '.pth'
        
        filepath = self.cache_dir / filename
        
        if filepath.exists():
            print(f"Using cached model: {filepath}")
            return str(filepath)
        
        print(f"Downloading model from {url}")
        response = requests.get(url, stream=True)
        response.raise_for_status()
        
        total_size = int(response.headers.get('content-length', 0))
        
        with open(filepath, 'wb') as f:
            with tqdm(total=total_size, unit='B', unit_scale=True) as pbar:
                for chunk in response.iter_content(chunk_size=8192):
                    if chunk:
                        f.write(chunk)
                        pbar.update(len(chunk))
        
        print(f"Model saved to {filepath}")
        return str(filepath)
    
    def load_checkpoint(self, url_or_path, map_location=None):
        if url_or_path.startswith('http://') or url_or_path.startswith('https://'):
            filepath = self.download_file(url_or_path)
        else:
            filepath = url_or_path
        
        checkpoint = torch.load(filepath, map_location=map_location)
        return checkpoint


class PretrainedModelLoader:
    def __init__(self, cache_dir='./model_cache'):
        self.downloader = ModelDownloader(cache_dir)
        
    def load_torchvision_model(self, model_name, pretrained=True):
        model_dict = {
            'resnet18': models.resnet18,
            'resnet34': models.resnet34,
            'resnet50': models.resnet50,
            'vgg16': models.vgg16,
            'densenet121': models.densenet121,
            'mobilenet_v2': models.mobilenet_v2,
        }
        
        if model_name not in model_dict:
            raise ValueError(f"Model {model_name} not supported")
        
        print(f"Loading {model_name} (pretrained={pretrained})")
        model = model_dict[model_name](pretrained=pretrained)
        return model
    
    def load_from_url(self, url, model_architecture, map_location=None):
        checkpoint = self.downloader.load_checkpoint(url, map_location)
        
        if isinstance(checkpoint, dict) and 'state_dict' in checkpoint:
            model_architecture.load_state_dict(checkpoint['state_dict'])
            return model_architecture, checkpoint
        else:
            model_architecture.load_state_dict(checkpoint)
            return model_architecture, None
    
    def load_custom_checkpoint(self, checkpoint_path, model_architecture=None):
        checkpoint = torch.load(checkpoint_path, map_location='cpu')
        
        if model_architecture is None:
            if 'model_config' in checkpoint:
                config = checkpoint['model_config']
                model_architecture = self.build_model_from_config(config)
        
        if isinstance(checkpoint, dict) and 'state_dict' in checkpoint:
            model_architecture.load_state_dict(checkpoint['state_dict'])
            return model_architecture, checkpoint
        else:
            model_architecture.load_state_dict(checkpoint)
            return model_architecture, None


class TransferLearningTrainer:
    def __init__(self, model, num_classes, device='cuda', freeze_backbone=True):
        self.device = torch.device(device if torch.cuda.is_available() else 'cpu')
        self.model = model.to(self.device)
        self.num_classes = num_classes
        
        self._modify_classifier(freeze_backbone)
        
        self.criterion = nn.CrossEntropyLoss()
        self.optimizer = None
        self.scheduler = None
        
    def _modify_classifier(self, freeze_backbone):
        if hasattr(self.model, 'fc'):
            if freeze_backbone:
                for param in self.model.parameters():
                    param.requires_grad = False
            
            num_features = self.model.fc.in_features
            self.model.fc = nn.Linear(num_features, self.num_classes)
            
        elif hasattr(self.model, 'classifier'):
            if freeze_backbone:
                for param in self.model.features.parameters():
                    param.requires_grad = False
            
            if isinstance(self.model.classifier, nn.Sequential):
                num_features = self.model.classifier[-1].in_features
                self.model.classifier[-1] = nn.Linear(num_features, self.num_classes)
            else:
                num_features = self.model.classifier.in_features
                self.model.classifier = nn.Linear(num_features, self.num_classes)
    
    def setup_optimizer(self, learning_rate=0.001, optimizer_type='adam'):
        if optimizer_type.lower() == 'adam':
            self.optimizer = optim.Adam(filter(lambda p: p.requires_grad, self.model.parameters()), 
                                       lr=learning_rate)
        elif optimizer_type.lower() == 'sgd':
            self.optimizer = optim.SGD(filter(lambda p: p.requires_grad, self.model.parameters()), 
                                      lr=learning_rate, momentum=0.9)
        
        self.scheduler = optim.lr_scheduler.StepLR(self.optimizer, step_size=7, gamma=0.1)
    
    def train_epoch(self, train_loader):
        self.model.train()
        running_loss = 0.0
        correct = 0
        total = 0
        
        pbar = tqdm(train_loader, desc='Training')
        for inputs, labels in pbar:
            inputs, labels = inputs.to(self.device), labels.to(self.device)
            
            self.optimizer.zero_grad()
            
            outputs = self.model(inputs)
            loss = self.criterion(outputs, labels)
            
            loss.backward()
            self.optimizer.step()
            
            running_loss += loss.item()
            _, predicted = outputs.max(1)
            total += labels.size(0)
            correct += predicted.eq(labels).sum().item()
            
            pbar.set_postfix({'loss': running_loss/total, 'acc': 100.*correct/total})
        
        epoch_loss = running_loss / len(train_loader)
        epoch_acc = 100. * correct / total
        return epoch_loss, epoch_acc
    
    def validate(self, val_loader):
        self.model.eval()
        running_loss = 0.0
        correct = 0
        total = 0
        
        with torch.no_grad():
            for inputs, labels in tqdm(val_loader, desc='Validation'):
                inputs, labels = inputs.to(self.device), labels.to(self.device)
                
                outputs = self.model(inputs)
                loss = self.criterion(outputs, labels)
                
                running_loss += loss.item()
                _, predicted = outputs.max(1)
                total += labels.size(0)
                correct += predicted.eq(labels).sum().item()
        
        val_loss = running_loss / len(val_loader)
        val_acc = 100. * correct / total
        return val_loss, val_acc
    
    def train(self, train_loader, val_loader, epochs=10):
        best_acc = 0.0
        history = {'train_loss': [], 'train_acc': [], 'val_loss': [], 'val_acc': []}
        
        for epoch in range(epochs):
            print(f'\nEpoch {epoch+1}/{epochs}')
            
            train_loss, train_acc = self.train_epoch(train_loader)
            val_loss, val_acc = self.validate(val_loader)
            
            history['train_loss'].append(train_loss)
            history['train_acc'].append(train_acc)
            history['val_loss'].append(val_loss)
            history['val_acc'].append(val_acc)
            
            print(f'Train Loss: {train_loss:.4f}, Train Acc: {train_acc:.2f}%')
            print(f'Val Loss: {val_loss:.4f}, Val Acc: {val_acc:.2f}%')
            
            if val_acc > best_acc:
                best_acc = val_acc
                self.save_checkpoint('best_model.pth', epoch, val_acc)
            
            if self.scheduler:
                self.scheduler.step()
        
        return history
    
    def save_checkpoint(self, filepath, epoch, accuracy):
        checkpoint = {
            'epoch': epoch,
            'model_state_dict': self.model.state_dict(),
            'optimizer_state_dict': self.optimizer.state_dict(),
            'accuracy': accuracy,
            'num_classes': self.num_classes
        }
        torch.save(checkpoint, filepath)
        print(f'Checkpoint saved to {filepath} (Acc: {accuracy:.2f}%)')


class CustomDataset(Dataset):
    def __init__(self, data, labels, transform=None):
        self.data = data
        self.labels = labels
        self.transform = transform
    
    def __len__(self):
        return len(self.data)
    
    def __getitem__(self, idx):
        sample = self.data[idx]
        label = self.labels[idx]
        
        if self.transform:
            sample = self.transform(sample)
        
        return sample, label


def create_data_loaders(train_dir, val_dir, batch_size=32, num_workers=4):
    train_transform = transforms.Compose([
        transforms.RandomResizedCrop(224),
        transforms.RandomHorizontalFlip(),
        transforms.ToTensor(),
        transforms.Normalize([0.485, 0.456, 0.406], [0.229, 0.224, 0.225])
    ])
    
    val_transform = transforms.Compose([
        transforms.Resize(256),
        transforms.CenterCrop(224),
        transforms.ToTensor(),
        transforms.Normalize([0.485, 0.456, 0.406], [0.229, 0.224, 0.225])
    ])
    
    train_dataset = ImageFolder(train_dir, transform=train_transform)
    val_dataset = ImageFolder(val_dir, transform=val_transform)
    
    train_loader = DataLoader(train_dataset, batch_size=batch_size, 
                             shuffle=True, num_workers=num_workers)
    val_loader = DataLoader(val_dataset, batch_size=batch_size, 
                           shuffle=False, num_workers=num_workers)
    
    return train_loader, val_loader, len(train_dataset.classes)


def fine_tune_pretrained_model(model_name='resnet18', train_dir='./data/train', 
                               val_dir='./data/val', epochs=10, learning_rate=0.001,
                               batch_size=32, freeze_backbone=True):
    loader = PretrainedModelLoader()
    model = loader.load_torchvision_model(model_name, pretrained=True)
    
    train_loader, val_loader, num_classes = create_data_loaders(
        train_dir, val_dir, batch_size=batch_size
    )
    
    trainer = TransferLearningTrainer(model, num_classes, freeze_backbone=freeze_backbone)
    trainer.setup_optimizer(learning_rate=learning_rate)
    
    history = trainer.train(train_loader, val_loader, epochs=epochs)
    
    return trainer.model, history


def fine_tune_from_url(model_url, model_architecture, train_dir='./data/train',
                       val_dir='./data/val', epochs=10, learning_rate=0.001,
                       batch_size=32, freeze_backbone=True):
    loader = PretrainedModelLoader()
    model, checkpoint = loader.load_from_url(model_url, model_architecture)
    
    train_loader, val_loader, num_classes = create_data_loaders(
        train_dir, val_dir, batch_size=batch_size
    )
    
    trainer = TransferLearningTrainer(model, num_classes, freeze_backbone=freeze_backbone)
    trainer.setup_optimizer(learning_rate=learning_rate)
    
    history = trainer.train(train_loader, val_loader, epochs=epochs)
    
    return trainer.model, history


